export const postAuthAdminHasPermissionMutation = (options?: Partial<Options<PostAuthAdminHasPermissionData>>): UseMutationOptions<PostAuthAdminHasPermissionResponse, PostAuthAdminHasPermissionError, Options<PostAuthAdminHasPermissionData>> => {
    const mutationOptions: UseMutationOptions<PostAuthAdminHasPermissionResponse, PostAuthAdminHasPermissionError, Options<PostAuthAdminHasPermissionData>> = {
        mutationFn: async (fnOptions) => {
            const { data } = await postAuthAdminHasPermission({
                ...options,
                ...fnOptions,
                throwOnError: true
            });
            return data;
        }
    };
    return mutationOptions;
};
